class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        if n == 1:
            return list(range(10))
        queue = list(range(1, 10))
        for _ in range(n - 1):
            next_queue = []
            for num in queue:
                last = num % 10
                for nxt in {last + k, last - k}:
                    if 0 <= nxt <= 9:
                        next_queue.append(num * 10 + nxt)
            queue = next_queue
        return queue
